const CFG = { SUPABASE_URL:"https://YOUR_PROJECT.supabase.co", SUPABASE_ANON_KEY:"YOUR_ANON_KEY" };
class SB {
  constructor(){this.token=null;this.user=null;}
  get h(){return{"Content-Type":"application/json",apikey:CFG.SUPABASE_ANON_KEY,Authorization:`Bearer ${this.token||CFG.SUPABASE_ANON_KEY}`,Prefer:"return=representation"};}
  async signUp(e,p,m={}){const r=await fetch(`${CFG.SUPABASE_URL}/auth/v1/signup`,{method:"POST",headers:{"Content-Type":"application/json",apikey:CFG.SUPABASE_ANON_KEY},body:JSON.stringify({email:e,password:p,data:m})});const d=await r.json();if(d?.access_token){this.token=d.access_token;this.user=d.user;}return{data:d,error:d.error?{message:d.error_description||d.error}:null};}
  async signIn(e,p){const r=await fetch(`${CFG.SUPABASE_URL}/auth/v1/token?grant_type=password`,{method:"POST",headers:{"Content-Type":"application/json",apikey:CFG.SUPABASE_ANON_KEY},body:JSON.stringify({email:e,password:p})});const d=await r.json();if(d?.access_token){this.token=d.access_token;this.user=d.user;}return{data:d,error:d.error?{message:d.error_description||d.error}:null};}
  async signOut(){await fetch(`${CFG.SUPABASE_URL}/auth/v1/logout`,{method:"POST",headers:this.h});this.token=null;this.user=null;}
  async getUser(){if(!this.token)return{data:{user:null}};const r=await fetch(`${CFG.SUPABASE_URL}/auth/v1/user`,{headers:this.h});if(!r.ok){this.token=null;return{data:{user:null}};}const d=await r.json();this.user=d;return{data:{user:d}};}
  from(t){return new QB(this,t);}
  realtime(table,cb){const url=`${CFG.SUPABASE_URL.replace("https://","wss://")}/realtime/v1/websocket?apikey=${CFG.SUPABASE_ANON_KEY}&vsn=1.0.0`;let ws,alive=true;const conn=()=>{try{ws=new WebSocket(url);ws.onopen=()=>ws.send(JSON.stringify({topic:`realtime:public:${table}`,event:"phx_join",payload:{config:{broadcast:{ack:false},postgres_changes:[{event:"*",schema:"public",table}]}},ref:"1"}));ws.onmessage=e=>{try{const m=JSON.parse(e.data);const p=m?.payload?.data;if(p)cb({type:p.type,record:p.record,old:p.old_record});}catch{}};ws.onclose=()=>{if(alive)setTimeout(conn,3000);};}catch{}};conn();return()=>{alive=false;ws?.close();};}
  channel(name){const url=`${CFG.SUPABASE_URL.replace("https://","wss://")}/realtime/v1/websocket?apikey=${CFG.SUPABASE_ANON_KEY}&vsn=1.0.0`;let ws,alive=true;const handlers={};const send=(ev,payload)=>{if(ws?.readyState===1)ws.send(JSON.stringify({topic:`realtime:${name}`,event:"broadcast",payload:{event:ev,payload},ref:"2"}));};const ch={on:(ev,cb2)=>{handlers[ev]=cb2;return ch;},send,subscribe:()=>{try{ws=new WebSocket(url);ws.onopen=()=>ws.send(JSON.stringify({topic:`realtime:${name}`,event:"phx_join",payload:{config:{broadcast:{ack:false,self:false}}},ref:"1"}));ws.onmessage=e=>{try{const m=JSON.parse(e.data);if(m.event==="broadcast"&&handlers[m.payload?.event])handlers[m.payload.event](m.payload?.payload);}catch{}};ws.onclose=()=>{if(alive)setTimeout(()=>ch.subscribe(),3000);};}catch{}return ch;},unsubscribe:()=>{alive=false;ws?.close();}};return ch;}
}
class QB {
  constructor(sb,t){this.sb=sb;this.t=t;this._sel="*";this._fil=[];this._ord=null;this._lim=null;this._sing=false;this._method="GET";this._body=null;this._ups=false;}
  select(s="*"){this._sel=s;return this;}eq(c,v){this._fil.push([c,`eq.${v}`]);return this;}neq(c,v){this._fil.push([c,`neq.${v}`]);return this;}ilike(c,v){this._fil.push([c,`ilike.${v}`]);return this;}or(q){this._fil.push(["or",q]);return this;}in(c,vs){this._fil.push([c,`in.(${vs.join(",")})`]);return this;}gte(c,v){this._fil.push([c,`gte.${v}`]);return this;}lt(c,v){this._fil.push([c,`lt.${v}`]);return this;}order(c,{ascending=true}={}){this._ord=`${c}.${ascending?"asc":"desc"}`;return this;}limit(n){this._lim=n;return this;}single(){this._sing=true;return this;}insert(d){this._method="POST";this._body=d;return this;}update(d){this._method="PATCH";this._body=d;return this;}upsert(d){this._method="POST";this._body=d;this._ups=true;return this;}delete(){this._method="DELETE";return this;}
  async then(res){const p=new URLSearchParams();if(this._method==="GET")p.set("select",this._sel);this._fil.forEach(([k,v])=>{if(k==="or")p.set("or",`(${v})`);else p.set(k,v);});if(this._ord)p.set("order",this._ord);if(this._lim)p.set("limit",String(this._lim));const h={...this.sb.h};if(this._ups)h.Prefer="return=representation,resolution=merge-duplicates";if(this._sing)h.Accept="application/vnd.pgrst.object+json";const url=`${CFG.SUPABASE_URL}/rest/v1/${this.t}?${p}`;try{const r=await fetch(url,{method:this._method,headers:h,body:this._body?JSON.stringify(this._body):undefined});if(r.status===204){res({data:null,error:null});return;}const d=await r.json();if(!r.ok){res({data:null,error:{message:d.message||d.hint||"Error"}});return;}res({data:d,error:null});}catch(e){res({data:null,error:{message:e.message}});}}
}
