const Av=({name="?",url,color,size=42,online,ring,status})=>{const t=T(),c=color||t.purple;const init=(name||"?").split(" ").map(w=>w[0]).join("").toUpperCase().slice(0,2);const sc=status==="away"?t.yellow:status==="dnd"?t.red:t.green;return <div style={{position:"relative",flexShrink:0,width:size,height:size}}>{url?<img src={url} alt={name} style={{width:size,height:size,borderRadius:"50%",objectFit:"cover",boxShadow:ring?`0 0 0 2px ${t.bg},0 0 0 3.5px ${c}`:"none"}}/>:<div style={{width:size,height:size,borderRadius:"50%",background:`linear-gradient(135deg,${c}bb,${c})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:size*0.34,fontWeight:800,color:"#fff",fontFamily:"'Sora',sans-serif",boxShadow:ring?`0 0 0 2px ${t.bg},0 0 0 3.5px ${c}`:`0 2px 10px ${c}50`}}>{init}</div>}{(online||status)&&<div style={{position:"absolute",bottom:0,right:0,width:Math.max(9,size*0.28),height:Math.max(9,size*0.28),borderRadius:"50%",background:sc,border:`${Math.max(2,size*0.05)}px solid ${t.bg}`,boxShadow:`0 0 6px ${sc}80`}}/>}</div>;};
