const Badge=({n,color,dot})=>{const t=T();if(!n&&!dot)return null;const c=color||t.red;if(dot)return <div style={{width:9,height:9,borderRadius:"50%",background:c,border:`2px solid ${t.bg}`,boxShadow:`0 0 6px ${c}80`}}/>;return <div style={{background:c,color:"#fff",fontSize:10,fontWeight:800,padding:"2px 6px",borderRadius:10,minWidth:19,textAlign:"center",fontFamily:"'Sora',sans-serif"}}>{n>99?"99+":n}</div>;};
