function StoryRing({size=52,seen,children}){const t=T();return <div style={{width:size+4,height:size+4,borderRadius:"50%",padding:2,background:seen?t.border:t.grad,flexShrink:0}}><div style={{width:"100%",height:"100%",borderRadius:"50%",background:t.bg,padding:2}}>{children}</div></div>;}
function StoryBar({profile,onView,onAdd,stories=[]}){const t=T();return <div style={{display:"flex",gap:12,padding:"10px 14px 14px",overflowX:"auto"}}><button onClick={onAdd} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:5,flexShrink:0,background:"none",border:"none",cursor:"pointer"}}><div style={{width:56,height:56,borderRadius:"50%",position:"relative"}}><Av name={profile.full_name||"?"} color={profile.avatar_color} size={56}/><div style={{position:"absolute",bottom:-2,right:-2,width:20,height:20,borderRadius:"50%",background:t.grad,display:"flex",alignItems:"center",justifyContent:"center",border:`2px solid ${t.bg}`}}><Plus size={11} color="#fff"/></div></div><span style={{fontSize:10,color:t.textSub,fontFamily:"'Sora',sans-serif",fontWeight:600}}>Add</span></button>{stories.map((s,i)=>{const seen=s.items?.every(x=>x.viewers?.includes?.(profile.id));return <button key={i} onClick={()=>onView(stories,i)} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:5,flexShrink:0,background:"none",border:"none",cursor:"pointer"}}><StoryRing size={52} seen={seen}><Av name={s.user?.full_name||"?"} color={s.user?.avatar_color} size={52}/></StoryRing><span style={{fontSize:10,color:t.textSub,fontFamily:"'Sora',sans-serif",fontWeight:600,maxWidth:56,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{s.user?.full_name?.split(" ")[0]}</span></button>;})}</div>;}
function StoryViewer({stories,startIdx=0,onClose,profile}){const t=T();const [si,setSi]=useState(startIdx);const [ii,setIi]=useState(0);const [paused,setPaused]=useState(false);const cur=stories[si];const items=cur?.items||[];const story=items[ii];useEffect(()=>{if(paused||!story)return;const x=setTimeout(()=>{if(ii<items.length-1)setIi(i=>i+1);else if(si<stories.length-1){setSi(s=>s+1);setIi(0);}else onClose();},5000);return()=>clearTimeout(x);},[ii,si,paused,items.length,stories.length,story]);if(!story)return null;return <div style={{position:"fixed",inset:0,zIndex:950,background:"#000",display:"flex",flexDirection:"column",maxWidth:430,margin:"0 auto"}} onMouseDown={()=>setPaused(true)} onMouseUp={()=>setPaused(false)} onTouchStart={()=>setPaused(true)} onTouchEnd={()=>setPaused(false)}><div style={{position:"absolute",inset:0,background:story.bg_color||"linear-gradient(135deg,#7c3aed,#0ea5e9)",opacity:.95}}/>{story.media_url&&<img src={story.media_url} style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover",opacity:.75}}/>}<div style={{position:"relative",zIndex:2,padding:"env(safe-area-inset-top,14px) 12px 0"}}><div style={{display:"flex",gap:4,marginBottom:10}}>{items.map((_,i)=><div key={i} style={{flex:1,height:2.5,borderRadius:2,background:"rgba(255,255,255,0.35)",overflow:"hidden"}}>{i<ii&&<div style={{height:"100%",background:"#fff"}}/>}{i===ii&&<div style={{height:"100%",background:"#fff",animation:"sProg 5s linear forwards",animationPlayState:paused?"paused":"running"}}/>}</div>)}</div><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 2px"}}><div style={{display:"flex",alignItems:"center",gap:10}}><Av name={cur.user?.full_name||"?"} color={cur.user?.avatar_color} size={36}/><div><div style={{color:"#fff",fontWeight:700,fontSize:14,fontFamily:"'Sora',sans-serif"}}>{cur.user?.full_name}</div><div style={{color:"rgba(255,255,255,0.6)",fontSize:11}}>{new Date(story.created_at||Date.now()).toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})}</div></div></div><button onClick={e=>{e.stopPropagation();onClose();}} style={{background:"rgba(0,0,0,0.4)",border:"none",borderRadius:"50%",width:32,height:32,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><X size={16} color="#fff"/></button></div></div>{story.content&&<div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",color:"#fff",fontSize:22,fontWeight:800,fontFamily:"'Sora',sans-serif",textAlign:"center",padding:24,textShadow:"0 3px 24px rgba(0,0,0,0.7)",maxWidth:340,zIndex:2,lineHeight:1.4}}>{story.content}</div>}<div style={{position:"absolute",bottom:0,left:0,right:0,padding:"16px 16px 44px",zIndex:2,background:"linear-gradient(transparent,rgba(0,0,0,0.55))"}}><div style={{display:"flex",alignItems:"center",gap:8}}><div style={{flex:1,background:"rgba(255,255,255,0.15)",borderRadius:24,padding:"10px 16px",border:"1px solid rgba(255,255,255,0.2)"}}><span style={{color:"rgba(255,255,255,0.55)",fontSize:13}}>Reply to story...</span></div><button style={{background:"rgba(255,255,255,0.15)",border:"none",borderRadius:"50%",width:42,height:42,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><Heart size={18} color="#fff"/></button></div></div><div style={{position:"absolute",left:0,top:0,bottom:0,width:"40%"}} onClick={e=>{e.stopPropagation();if(ii>0)setIi(i=>i-1);else if(si>0){setSi(s=>s-1);setIi(0);}}}/><div style={{position:"absolute",right:0,top:0,bottom:0,width:"40%"}} onClick={e=>{e.stopPropagation();if(ii<items.length-1)setIi(i=>i+1);else if(si<stories.length-1){setSi(s=>s+1);setIi(0);}else onClose();}}/></div>;}
function AddStorySheet({open,onClose,profile,onAdded}){const t=T();const [content,setContent]=useState("");const [bg,setBg]=useState("#7c3aed");const [posting,setPosting]=useState(false);const bgs=["#7c3aed","#0ea5e9","#ef4444","#f59e0b","#10b981","#ec4899","#000","linear-gradient(135deg,#7c3aed,#00cfff)","linear-gradient(135deg,#ef4444,#f59e0b)","linear-gradient(135deg,#10b981,#0ea5e9)","linear-gradient(135deg,#ec4899,#8b5cf6)","linear-gradient(135deg,#1a1a2e,#16213e)"];const post=async()=>{if(!content.trim())return;setPosting(true);await sb.from("stories").insert({user_id:profile.id,content,type:"text",bg_color:bg,expires_at:new Date(Date.now()+86400000).toISOString()});setPosting(false);onAdded?.();onClose();setContent("");};return <Sheet title="Create Story" open={open} onClose={onClose} icon={<PlayCircle size={16} color={t.pink}/>}><div style={{borderRadius:16,height:190,background:bg,display:"flex",alignItems:"center",justifyContent:"center",marginBottom:14}}>{content?<div style={{color:"#fff",fontSize:20,fontWeight:800,textAlign:"center",padding:16,textShadow:"0 2px 12px rgba(0,0,0,0.5)",fontFamily:"'Sora',sans-serif",lineHeight:1.4}}>{content}</div>:<div style={{color:"rgba(255,255,255,0.4)",fontSize:13,fontFamily:"'Sora',sans-serif"}}>Preview</div>}</div><div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>{bgs.map((c,i)=><button key={i} onClick={()=>setBg(c)} style={{width:34,height:34,borderRadius:9,background:c,border:`2.5px solid ${bg===c?"#fff":"transparent"}`,cursor:"pointer",flexShrink:0}}/>)}</div><Inp value={content} onChange={e=>setContent(e.target.value)} placeholder="What's on your mind?" multiline rows={2}/><Btn full icon={PlayCircle} onClick={post} loading={posting} disabled={!content.trim()} style={{justifyContent:"center"}}>Post Story (24h)</Btn></Sheet>;}

// ═══════════════════════════════════════════════════════
// CHAT WINDOW
// ═══════════════════════════════════════════════════════
function ChatWin({chat,profile,onBack,onOpenInfo}){
  const t=T();const [msgs,setMsgs]=useState([]);const [input,setInput]=useState("");const [ld,setLd]=useState(true);const [replyTo,setReplyTo]=useState(null);const [editMsg,setEditMsg]=useState(null);const [ctxMenu,setCtxMenu]=useState(null);const [peer,setPeer]=useState(null);const [canSend,setCanSend]=useState(true);const [peerTyping,setPeerTyping]=useState(false);const [pinned,setPinned]=useState(null);const [showAttach,setShowAttach]=useState(false);const [showSticker,setShowSticker]=useState(false);const [showPoll,setShowPoll]=useState(false);const [showForward,setShowForward]=null&&useState(null);const [showVoice,setShowVoice]=useState(false);const [showQuick,setShowQuick]=useState(false);const [chatTheme,setChatTheme]=useState(CHAT_THEMES[0]);const [emojiPicker,setEmojiPicker]=useState(null);
  const endRef=useRef(null);const inputRef=useRef(null);const typCh=useRef(null);const typTo=useRef(null);const msgRefs=useRef({});

  useEffect(()=>{(async()=>{setLd(true);const {data}=await sb.from("messages").select("*").eq("chat_id",chat.id).eq("is_deleted",false).order("created_at",{ascending:true}).limit(100);setMsgs(data||[]);setLd(false);const {data:p}=await sb.from("pinned_messages").select("*,messages(*)").eq("chat_id",chat.id).limit(1).single();if(p?.messages)setPinned(p.messages);if(data?.length){const u=data.filter(m=>m.sender_id!==profile.id).map(m=>({message_id:m.id,user_id:profile.id}));if(u.length)await sb.from("message_reads").upsert(u);}})();},[chat.id,profile.id]);
  useEffect(()=>{if(chat.type==="personal"){(async()=>{const {data:m}=await sb.from("chat_members").select("user_id").eq("chat_id",chat.id).neq("user_id",profile.id).single();if(m){const {data:p}=await sb.from("profiles").select("*").eq("id",m.user_id).single();setPeer(p);}})();}if(chat.who_can_send==="admins"){sb.from("chat_members").select("role").eq("chat_id",chat.id).eq("user_id",profile.id).single().then(({data})=>setCanSend(data?.role==="owner"||data?.role==="admin"));}},[chat,profile.id]);
  useEffect(()=>{const ch=sb.channel(`typ_${chat.id}`);typCh.current=ch;ch.on("typing",({user_id})=>{if(user_id!==profile.id){setPeerTyping(true);clearTimeout(typTo.current);typTo.current=setTimeout(()=>setPeerTyping(false),3500);}}).subscribe();return()=>{ch.unsubscribe();clearTimeout(typTo.current);};},[chat.id,profile.id]);
  useEffect(()=>sb.realtime("messages",({type:ev,record})=>{if(record.chat_id!==chat.id)return;if(ev==="INSERT"&&!record.is_deleted){setMsgs(prev=>{if(prev.find(m=>m.id===record.id))return prev;return[...prev,record];});if(record.sender_id!==profile.id)sb.from("message_reads").upsert([{message_id:record.id,user_id:profile.id}]);}if(ev==="UPDATE")setMsgs(prev=>prev.map(m=>m.id===record.id?{...m,...record}:m));}),[chat.id,profile.id]);
  useEffect(()=>{endRef.current?.scrollIntoView({behavior:"smooth"});},[msgs,peerTyping]);
  const sendTyping=()=>{if(typCh.current&&input)typCh.current.send("typing",{user_id:profile.id,chat_id:chat.id});};
  const send=async(text=null,type="text",extra={})=>{const content=text||input.trim();if(!content&&type==="text")return;if(!canSend)return;if(editMsg){await sb.from("messages").update({content,is_edited:true,edited_at:new Date().toISOString()}).eq("id",editMsg.id);setMsgs(prev=>prev.map(m=>m.id===editMsg.id?{...m,content,is_edited:true}:m));setEditMsg(null);setInput("");return;}setInput("");const payload={chat_id:chat.id,sender_id:profile.id,content,type,reply_to_id:replyTo?.id||null,...extra};setReplyTo(null);const tid="t_"+Date.now();setMsgs(prev=>[...prev,{...payload,id:tid,created_at:new Date().toISOString(),_tmp:true}]);const {data,error}=await sb.from("messages").insert(payload).single();if(error)setMsgs(prev=>prev.filter(m=>m.id!==tid));else setMsgs(prev=>prev.map(m=>m.id===tid?data:m));};
  const react=async(msgId,emoji)=>{const msg=msgs.find(m=>m.id===msgId);if(!msg)return;const r={...msg.reactions||{}};const arr=r[emoji]||[];const na=arr.includes(profile.id)?arr.filter(x=>x!==profile.id):[...arr,profile.id];if(na.length)r[emoji]=na;else delete r[emoji];await sb.from("messages").update({reactions:r}).eq("id",msgId);setMsgs(prev=>prev.map(m=>m.id===msgId?{...m,reactions:r}:m));setEmojiPicker(null);};
  const delMsg=async m=>{await sb.from("messages").update({is_deleted:true}).eq("id",m.id);setMsgs(prev=>prev.filter(x=>x.id!==m.id));};
  const grouped=useMemo(()=>{const g=[];let ld=null;msgs.forEach(m=>{if(m.is_deleted)return;const d=new Date(m.created_at).toDateString();if(d!==ld){g.push({t:"date",d});ld=d;}g.push({t:"msg",m});});return g;},[msgs]);
  const dname=chat.type==="personal"?(peer?.full_name||"User"):chat.name;const dcolor=chat.type==="personal"?(peer?.avatar_color||t.purple):(chat.avatar_color||t.purple);
  const bgS=chatTheme.css?{backgroundImage:chatTheme.css,backgroundSize:chatTheme.size||"auto"}:{};
  const ctxItems=(m,isMe)=>[{icon:Reply,label:"Reply",action:()=>{setReplyTo(m);inputRef.current?.focus();}},{icon:Copy,label:"Copy",action:()=>navigator.clipboard?.writeText(m.content)},{icon:Forward,label:"Forward",action:()=>{}},{icon:Bookmark,label:"Save",action:()=>sb.from("saved_messages").insert({user_id:profile.id,message_id:m.id})},{icon:Pin,label:"Pin",action:async()=>{await sb.from("pinned_messages").upsert({chat_id:chat.id,message_id:m.id,pinned_by:profile.id});setPinned(m);}},isMe&&{icon:Edit3,label:"Edit",action:()=>{setEditMsg(m);setInput(m.content);inputRef.current?.focus();}},isMe&&{icon:Lock,label:"Secret Mode"},"div",isMe?{icon:Trash2,label:"Delete",danger:true,action:()=>delMsg(m)}:{icon:Flag,label:"Report",danger:true}].filter(Boolean);
  return <div style={{display:"flex",flexDirection:"column",height:"100vh",background:t.bg,...bgS}} onClick={()=>{setCtxMenu(null);setShowAttach(false);setShowSticker(false);setEmojiPicker(null);}}>
    {/* HEADER */}
    <div style={{display:"flex",alignItems:"center",gap:10,padding:"11px 12px",background:`${t.surface}ee`,borderBottom:`1px solid ${t.border}`,paddingTop:"calc(11px + env(safe-area-inset-top,0px))",backdropFilter:"blur(14px)",position:"relative",zIndex:50}}>
      <button onClick={onBack} style={{background:"none",border:"none",cursor:"pointer",color:t.accent,padding:6,flexShrink:0}}><ArrowLeft size={22}/></button>
      <button onClick={()=>onOpenInfo(chat)} style={{background:"none",border:"none",cursor:"pointer",display:"flex",alignItems:"center",gap:10,flex:1,minWidth:0}}>
        <Av name={dname} color={dcolor} size={40} online={chat.type==="personal"}/>
        <div style={{textAlign:"left",minWidth:0}}>
          <div style={{display:"flex",alignItems:"center",gap:5}}><span style={{fontFamily:"'Sora',sans-serif",fontWeight:700,color:t.text,fontSize:15,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{dname}</span>{chat.is_verified&&<Vtick/>}<E2ETag/></div>
          <div style={{fontSize:11,color:peerTyping?t.accent:t.textSub,fontStyle:peerTyping?"italic":"normal",fontFamily:"'Sora',sans-serif"}}>{peerTyping?"typing...":chat.type==="personal"?peer?.is_online?"● Online":"Last seen recently":`${(chat.member_count||0).toLocaleString()} members`}</div>
        </div>
      </button>
      <div style={{display:"flex",gap:2,flexShrink:0}}>
        {chat.type==="personal"&&<><button style={{background:"none",border:"none",cursor:"pointer",color:t.textSub,padding:8,borderRadius:10}}><Phone size={18}/></button><button style={{background:"none",border:"none",cursor:"pointer",color:t.textSub,padding:8,borderRadius:10}}><Video size={18}/></button></>}
        <button onClick={e=>{e.stopPropagation();setCtxMenu({hdr:true,x:e.clientX,y:e.clientY});}} style={{background:"none",border:"none",cursor:"pointer",color:t.textSub,padding:8,borderRadius:10}}><MoreVertical size={18}/></button>
      </div>
      {ctxMenu?.hdr&&<ContextMenu pos={{x:ctxMenu.x,y:ctxMenu.y}} onClose={()=>setCtxMenu(null)} items={[{icon:Info,label:"Chat Info",action:()=>onOpenInfo(chat)},{icon:Pin,label:"Pinned Messages"},{icon:Palette,label:"Chat Theme"},{icon:Timer,label:"Disappearing Messages"},{icon:Lock,label:"Secret Chat Mode"},"div",{icon:VolumeX,label:"Mute"},{icon:Archive,label:"Archive"},"div",{icon:Trash2,label:"Clear History",danger:true}]}/>}
    </div>
    {pinned&&<div style={{padding:"7px 14px",background:`${t.card}cc`,borderBottom:`1px solid ${t.border}`,display:"flex",alignItems:"center",gap:8,cursor:"pointer",backdropFilter:"blur(8px)"}} onClick={()=>{}}>
      <Pin size={12} color={t.accent}/><div style={{flex:1,fontSize:12,color:t.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontFamily:"'Sora',sans-serif"}}><span style={{color:t.accent,fontWeight:700}}>Pinned: </span>{pinned.content}</div>
      <button onClick={e=>{e.stopPropagation();setPinned(null);}} style={{background:"none",border:"none",cursor:"pointer",color:t.muted}}><X size={12}/></button>
    </div>}
    {/* MESSAGES */}
    <div style={{flex:1,overflowY:"auto",padding:"10px 12px 8px",display:"flex",flexDirection:"column",gap:2}}>
      {ld&&<div style={{display:"flex",justifyContent:"center",padding:30}}><Spin/></div>}
      {grouped.map((item,idx2)=>{
        if(item.t==="date")return <div key={"d"+idx2} style={{display:"flex",alignItems:"center",gap:10,margin:"14px 0 8px"}}><div style={{flex:1,height:1,background:t.border}}/><div style={{fontSize:10,color:t.textSub,background:`${t.elevated}dd`,padding:"3px 12px",borderRadius:8,flexShrink:0,backdropFilter:"blur(4px)",fontFamily:"'Sora',sans-serif"}}>{item.d===new Date().toDateString()?"Today":item.d}</div><div style={{flex:1,height:1,background:t.border}}/></div>;
        const m=item.m;const isMe=m.sender_id===profile.id;const rep=m.reply_to_id?msgs.find(r=>r.id===m.reply_to_id):null;
        return <div key={m.id} ref={el=>{if(el)msgRefs.current[m.id]=el;}} style={{display:"flex",justifyContent:isMe?"flex-end":"flex-start",marginBottom:1}}>
          <div style={{maxWidth:"78%",position:"relative"}} onContextMenu={e=>{e.preventDefault();e.stopPropagation();setCtxMenu({id:m.id,x:e.clientX,y:e.clientY,m,isMe});}}>
            {m.forward_from_id&&<div style={{fontSize:10,color:t.accent,display:"flex",alignItems:"center",gap:4,marginBottom:3,paddingLeft:4,fontFamily:"'Sora',sans-serif",fontWeight:700}}><Forward size={10}/>Forwarded</div>}
            {rep&&<div style={{background:`${t.elevated}cc`,borderRadius:"10px 10px 0 0",padding:"6px 12px",borderLeft:`3px solid ${t.accent}`,marginBottom:-2}}><div style={{fontSize:10,color:t.accent,fontWeight:700,marginBottom:1,fontFamily:"'Sora',sans-serif"}}>↩ Reply</div><div style={{fontSize:11,color:t.textSub,maxWidth:200,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{rep.content}</div></div>}
            <div style={{padding:m.type==="poll"?"12px":"9px 13px",borderRadius:isMe?"18px 18px 4px 18px":"18px 18px 18px 4px",background:isMe?t.msgSent:t.msgRecv,opacity:m._tmp?0.6:1,border:isMe?"none":`1px solid ${t.border}`,boxShadow:isMe?`0 2px 14px ${t.purple}30`:"none"}}>
              {m.type==="text"&&<div style={{color:t.text,fontSize:14,lineHeight:1.65,fontFamily:"'Sora',sans-serif",wordBreak:"break-word"}}>{m.content}</div>}
              {m.type==="sticker"&&<div style={{fontSize:48,lineHeight:1.2,padding:"4px 0"}}>{m.content}</div>}
              {m.type==="voice"&&<div style={{display:"flex",alignItems:"center",gap:10,minWidth:180}}><button style={{width:36,height:36,borderRadius:"50%",background:"rgba(255,255,255,0.15)",border:"none",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><PlayCircle size={18} color="#fff"/></button><VoiceWave len={24} active={false}/><span style={{fontSize:11,color:"rgba(255,255,255,0.5)",flexShrink:0,fontFamily:"'Sora',sans-serif"}}>{m.duration_secs||0}s</span></div>}
              {m.type==="poll"&&m.poll_data&&<PollView poll={m.poll_data} msgId={m.id} uid={profile.id} onVote={async(mid,optIdx)=>{const msg2=msgs.find(x=>x.id===mid);if(!msg2?.poll_data)return;const pd={...msg2.poll_data};pd.votes=(pd.votes||pd.options.map(()=>[]));pd.votes[optIdx]=[...(pd.votes[optIdx]||[]),profile.id];await sb.from("messages").update({poll_data:pd}).eq("id",mid);setMsgs(prev=>prev.map(x=>x.id===mid?{...x,poll_data:pd}:x));}}/>}
              <ReactBar reactions={m.reactions} msgId={m.id} uid={profile.id} onReact={react}/>
              {/* Emoji quick picker */}
              {emojiPicker===m.id&&<div style={{position:"absolute",[isMe?"right":"left"]:0,bottom:"105%",background:t.elevated,borderRadius:14,padding:8,display:"flex",gap:5,border:`1px solid ${t.border}`,boxShadow:`0 8px 28px #00000060`,zIndex:200}} onClick={e=>e.stopPropagation()}>
                {EMOJI_REACTIONS.slice(0,8).map(em=><button key={em} onClick={()=>react(m.id,em)} style={{background:"none",border:"none",cursor:"pointer",fontSize:20,padding:3,borderRadius:8,transition:"transform .1s"}} onMouseEnter={e=>e.target.style.transform="scale(1.3)"} onMouseLeave={e=>e.target.style.transform="scale(1)"}>{em}</button>)}
              </div>}
              <div style={{display:"flex",alignItems:"center",justifyContent:"flex-end",gap:5,marginTop:m.type==="poll"?8:3}}>
                {m.is_edited&&<span style={{fontSize:9,color:"rgba(255,255,255,0.35)",fontStyle:"italic"}}>edited</span>}
                <span style={{fontSize:10,color:"rgba(255,255,255,0.4)",fontFamily:"'Sora',sans-serif"}}>{new Date(m.created_at).toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})}</span>
                {isMe&&(m._tmp?<Clock size={10} color="rgba(255,255,255,0.3)"/>:<CheckCheck size={10} color={t.accent}/>)}
              </div>
            </div>
            {/* Long press emoji shortcut */}
            <button onClick={e=>{e.stopPropagation();setEmojiPicker(emojiPicker===m.id?null:m.id);}} style={{position:"absolute",top:"-4px",[isMe?"left":"right"]:"-4px",background:t.card,border:`1px solid ${t.border}`,borderRadius:"50%",width:24,height:24,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",opacity:0,transition:"opacity .15s",fontSize:12}} className="react-btn">😊</button>
          </div>
        </div>;
      })}
      {peerTyping&&<div style={{display:"flex",justifyContent:"flex-start",paddingLeft:4,marginBottom:4}}><TypingDots/></div>}
      <div ref={endRef}/>
    </div>
    {ctxMenu&&!ctxMenu.hdr&&<ContextMenu pos={{x:ctxMenu.x,y:ctxMenu.y}} onClose={()=>setCtxMenu(null)} items={ctxItems(ctxMenu.m,ctxMenu.isMe)}/>}
    {/* Sticker picker */}
    {showSticker&&<div style={{background:t.surface,borderTop:`1px solid ${t.border}`}} onClick={e=>e.stopPropagation()}>
      <div style={{display:"flex",gap:4,padding:"10px 12px 8px",borderBottom:`1px solid ${t.border}`,overflowX:"auto"}}>{STICKER_CATS.map(c=><button key={c} onClick={()=>{}} style={{width:36,height:36,borderRadius:10,background:t.card,border:`1px solid ${t.border}`,cursor:"pointer",fontSize:18,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"}}>{c}</button>)}</div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(6,1fr)",gap:4,padding:"10px 12px",maxHeight:180,overflowY:"auto"}}>{(STICKERS[STICKER_CATS[0]]||[]).map(em=><button key={em} onClick={()=>{send(em,"sticker");setShowSticker(false);}} style={{background:"none",border:"none",cursor:"pointer",fontSize:24,padding:"6px",borderRadius:10}}>{em}</button>)}</div>
    </div>}
    {/* Quick replies */}
    {showQuick&&<div style={{display:"flex",gap:6,padding:"8px 14px",overflowX:"auto",borderTop:`1px solid ${t.border}`,background:t.surface}}>
      {QUICK_REPLIES.map(r=><button key={r} onClick={()=>{setInput(r);setShowQuick(false);inputRef.current?.focus();}} style={{padding:"5px 12px",borderRadius:16,background:t.card,border:`1px solid ${t.border}`,color:t.text,fontSize:12,fontWeight:600,cursor:"pointer",flexShrink:0,fontFamily:"'Sora',sans-serif"}}>{r}</button>)}
    </div>}
    {/* Attach menu */}
    {showAttach&&<div style={{background:t.surface,borderTop:`1px solid ${t.border}`,padding:"10px 14px 14px"}} onClick={e=>e.stopPropagation()}>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10}}>
        {[{icon:FileImage,label:"Photo",color:t.purple,action:()=>{}},{icon:FileText,label:"Document",color:t.accent,action:()=>{}},{icon:BarChart3,label:"Poll",color:t.green,action:()=>{setShowPoll(true);setShowAttach(false);}},{icon:MapPin,label:"Location",color:t.red,action:()=>{}},{icon:Sticker,label:"Sticker",color:t.orange,action:()=>{setShowSticker(true);setShowAttach(false);}},{icon:Lightning,label:"GIF",color:t.pink,action:()=>{}},{icon:CalendarClock,label:"Schedule",color:t.yellow,action:()=>{}},{icon:User,label:"Contact",color:t.teal,action:()=>{}}].map(item=><button key={item.label} onClick={item.action} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:7,padding:"12px 4px",background:t.card,borderRadius:14,border:`1px solid ${t.border}`,cursor:"pointer"}}><div style={{width:40,height:40,borderRadius:12,background:`${item.color}20`,display:"flex",alignItems:"center",justifyContent:"center"}}><item.icon size={18} color={item.color}/></div><span style={{fontSize:10,color:t.textSub,fontFamily:"'Sora',sans-serif",fontWeight:600}}>{item.label}</span></button>)}
      </div>
    </div>}
    {/* Poll creator */}
    {showPoll&&<div style={{position:"fixed",inset:0,zIndex:600,background:"rgba(0,0,0,0.88)",backdropFilter:"blur(8px)",display:"flex",alignItems:"center",justifyContent:"center",padding:20}} onClick={()=>setShowPoll(false)}>
      <div style={{background:t.surface,borderRadius:22,padding:24,width:"100%",maxWidth:380,border:`1px solid ${t.border}`}} onClick={e=>e.stopPropagation()}>
        <div style={{fontWeight:700,color:t.text,fontSize:16,marginBottom:18,fontFamily:"'Sora',sans-serif"}}>📊 Create Poll</div>
        <Inp label="Question" placeholder="Ask something..." autoFocus value="" onChange={()=>{}}/>
        {["Option 1","Option 2","Option 3"].map((pl,i)=><Inp key={i} placeholder={pl} value="" onChange={()=>{}}/>)}
        <div style={{display:"flex",gap:10,marginTop:4}}><Btn variant="ghost" onClick={()=>setShowPoll(false)} style={{flex:1,justifyContent:"center"}}>Cancel</Btn><Btn style={{flex:2,justifyContent:"center"}} icon={BarChart3} onClick={()=>{send("Sample poll","poll",{poll_data:{question:"Sample question?",options:["Option 1","Option 2","Option 3"],votes:[[],[],[]],is_anonymous:true}});setShowPoll(false);}}>Create</Btn></div>
      </div>
    </div>}
    {/* Voice recorder */}
    {showVoice&&<div style={{padding:"8px 12px",background:t.surface,borderTop:`1px solid ${t.border}`}}>
      <div style={{background:`${t.red}14`,border:`1px solid ${t.red}40`,borderRadius:16,padding:"12px 16px",display:"flex",alignItems:"center",gap:12}}>
        <div style={{width:11,height:11,borderRadius:"50%",background:t.red,boxShadow:`0 0 8px ${t.red}`,animation:"pDot 1s ease-in-out infinite",flexShrink:0}}/>
        <div style={{flex:1}}><div style={{fontSize:12,color:t.red,fontWeight:700,marginBottom:4,fontFamily:"'Sora',sans-serif"}}>Recording...</div><VoiceWave len={28} active={true}/></div>
        <button onClick={()=>setShowVoice(false)} style={{width:36,height:36,borderRadius:"50%",background:t.card,border:`1px solid ${t.border}`,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><Trash2 size={15} color={t.textSub}/></button>
        <button onClick={()=>{send("Voice message","voice",{duration_secs:12});setShowVoice(false);}} style={{width:36,height:36,borderRadius:"50%",background:t.gradG,border:"none",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><Send size={15} color="#fff"/></button>
      </div>
    </div>}
    {/* Reply / Edit bar */}
    {(replyTo||editMsg)&&<div style={{background:`${t.surface}ee`,borderTop:`1px solid ${t.border}`,padding:"8px 14px",display:"flex",alignItems:"center",gap:10,backdropFilter:"blur(8px)"}}>
      {replyTo?<Reply size={14} color={t.accent}/>:<Edit3 size={14} color={t.yellow}/>}
      <div style={{flex:1,fontSize:12,color:t.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontFamily:"'Sora',sans-serif"}}><span style={{color:replyTo?t.accent:t.yellow,fontWeight:700}}>{replyTo?"Reply":"Edit"}: </span>{(replyTo||editMsg)?.content}</div>
      <button onClick={()=>{setReplyTo(null);setEditMsg(null);setInput("");}} style={{background:"none",border:"none",cursor:"pointer",color:t.muted}}><X size={14}/></button>
    </div>}
    {/* INPUT */}
    <div style={{padding:"8px 10px",background:`${t.surface}f2`,borderTop:`1px solid ${t.border}`,paddingBottom:"calc(8px + env(safe-area-inset-bottom,0px))",backdropFilter:"blur(14px)"}}>
      {!canSend?<div style={{textAlign:"center",padding:"10px",color:t.textSub,fontSize:12,fontFamily:"'Sora',sans-serif",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}><Lock size={13}/>Only admins can send messages</div>
      :<div style={{display:"flex",alignItems:"center",gap:8}}>
        <button onClick={e=>{e.stopPropagation();setShowAttach(!showAttach);setShowSticker(false);setShowQuick(false);}} style={{background:showAttach?`${t.purple}25`:"none",border:"none",cursor:"pointer",color:showAttach?t.accent:t.textSub,padding:8,borderRadius:12,transition:"all .2s"}}><Plus size={22}/></button>
        <div style={{flex:1,background:t.card,borderRadius:24,padding:"9px 14px",display:"flex",alignItems:"center",gap:8,border:`1px solid ${t.border}`}}>
          <input ref={inputRef} value={input} onChange={e=>{setInput(e.target.value);sendTyping();}} onKeyDown={e=>e.key==="Enter"&&!e.shiftKey&&(e.preventDefault(),send())} placeholder="Message..." style={{flex:1,background:"none",border:"none",outline:"none",color:t.text,fontSize:14,fontFamily:"'Sora',sans-serif",caretColor:t.accent}}/>
          <button onClick={e=>{e.stopPropagation();setShowSticker(!showSticker);setShowAttach(false);}} style={{background:"none",border:"none",cursor:"pointer",color:showSticker?t.accent:t.textSub,padding:2}}><Smile size={18}/></button>
          <button onClick={e=>{e.stopPropagation();setShowQuick(!showQuick);}} style={{background:"none",border:"none",cursor:"pointer",color:t.textSub,padding:2}}><Lightning size={15}/></button>
        </div>
        {!input.trim()?<button onMouseDown={e=>{e.preventDefault();setShowVoice(true);}} style={{width:44,height:44,borderRadius:"50%",border:"none",cursor:"pointer",background:t.card,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Mic size={18} color={t.textSub}/></button>
        :<button onClick={()=>send()} style={{width:44,height:44,borderRadius:"50%",border:"none",cursor:"pointer",background:t.grad,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,boxShadow:`0 3px 14px ${t.purple}55`,animation:"popIn .2s ease"}}><Send size={18} color="#fff"/></button>}
      </div>}
    </div>
  </div>;
}

// ═══════════════════════════════════════════════════════
// CHAT INFO PAGE
// ═══════════════════════════════════════════════════════
function ChatInfo({chat,profile,onBack}){
  const t=T();const [members,setMembers]=useState([]);const [tab,setTab]=useState("members");const [inviteLinks,setInviteLinks]=useState([]);
  useEffect(()=>{(async()=>{const {data:m}=await sb.from("chat_members").select("*,profiles:user_id(id,full_name,username,avatar_color,is_verified,is_online)").eq("chat_id",chat.id).order("role");setMembers(m||[]);const {data:l}=await sb.from("invite_links").select("*").eq("chat_id",chat.id).eq("is_revoked",false);setInviteLinks(l||[]);})();},[chat.id]);
  const createLink=async()=>{const {data}=await sb.from("invite_links").insert({chat_id:chat.id,created_by:profile.id}).single();if(data)setInviteLinks(l=>[data,...l]);};
  const revokeLink=async id=>{await sb.from("invite_links").update({is_revoked:true}).eq("id",id);setInviteLinks(l=>l.filter(x=>x.id!==id));};
  const roleColor=r=>r==="owner"?t.yellow:r==="admin"?t.orange:t.textSub;
  const tabs=[{id:"members",label:`Members (${members.length})`},{id:"links",label:"Invite Links"},{id:"settings",label:"Settings"}];
  return <div style={{display:"flex",flexDirection:"column",height:"100vh",background:t.bg,fontFamily:"'Sora',sans-serif"}}>
    <div style={{display:"flex",alignItems:"center",gap:12,padding:"12px 16px",background:t.surface,borderBottom:`1px solid ${t.border}`,paddingTop:"calc(12px + env(safe-area-inset-top,0px))"}}>
      <button onClick={onBack} style={{background:"none",border:"none",cursor:"pointer",color:t.accent}}><ArrowLeft size={22}/></button><span style={{fontWeight:700,color:t.text,fontSize:17}}>Chat Info</span>
    </div>
    <div style={{padding:"18px 16px 0",textAlign:"center"}}>
      <Av name={chat.name||"?"} color={chat.avatar_color||t.purple} size={74} ring/>
      <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:6,marginTop:12}}><span style={{fontWeight:800,color:t.text,fontSize:20}}>{chat.name}</span>{chat.is_verified&&<Vtick/>}</div>
      <div style={{color:t.textSub,fontSize:13,marginTop:4}}>{chat.type} · {chat.member_count||0} members{chat.username?` · @${chat.username}`:""}</div>
      {chat.description&&<div style={{marginTop:10,fontSize:13,color:t.textSub,lineHeight:1.6,background:t.card,borderRadius:12,padding:"10px 14px",textAlign:"left",border:`1px solid ${t.border}`}}>{chat.description}</div>}
      <div style={{display:"flex",gap:10,marginTop:14,justifyContent:"center"}}><Btn small icon={UserPlus} variant="success">Add</Btn><Btn small icon={Share2} variant="secondary">Share</Btn><Btn small icon={Bell} variant="secondary">Mute</Btn>{chat.type==="channel"&&<Btn small icon={BarChart2}>Analytics</Btn>}</div>
    </div>
    <div style={{padding:"14px 16px 0",overflowX:"auto"}}><div style={{display:"flex",gap:6,paddingBottom:8}}>{tabs.map(tb=><button key={tb.id} onClick={()=>setTab(tb.id)} style={{padding:"7px 14px",borderRadius:20,border:"none",flexShrink:0,cursor:"pointer",fontFamily:"'Sora',sans-serif",fontWeight:700,fontSize:12,transition:"all .2s",background:tab===tb.id?t.grad:t.surface,color:tab===tb.id?"#fff":t.textSub}}>{tb.label}</button>)}</div></div>
    <div style={{flex:1,overflowY:"auto",padding:"8px 16px 80px"}}>
      {tab==="members"&&members.map((m,i)=><div key={m.id} style={{display:"flex",alignItems:"center",gap:12,padding:"11px 0",borderBottom:i<members.length-1?`1px solid ${t.border}`:"none"}}>
        <Av name={m.profiles?.full_name||"?"} color={m.profiles?.avatar_color||t.purple} size={42} online={m.profiles?.is_online}/>
        <div style={{flex:1,minWidth:0}}><div style={{fontWeight:700,color:t.text,fontSize:14,display:"flex",alignItems:"center",gap:5}}>{m.profiles?.full_name}{m.profiles?.is_verified&&<Vtick/>}</div><div style={{fontSize:11,color:t.textSub}}>@{m.profiles?.username}</div></div>
        {m.role!=="member"&&<div style={{padding:"3px 9px",borderRadius:7,background:`${roleColor(m.role)}18`,fontSize:10,fontWeight:800,color:roleColor(m.role),textTransform:"capitalize"}}>{m.role}</div>}
        <button style={{background:"none",border:"none",cursor:"pointer",color:t.muted,padding:4}}><MoreVertical size={15}/></button>
      </div>)}
      {tab==="links"&&<>
        <Btn full icon={Link} onClick={createLink} style={{marginBottom:16,justifyContent:"center"}}>Generate Invite Link</Btn>
        {inviteLinks.map(l=><div key={l.id} style={{background:t.surface,borderRadius:14,padding:"12px 14px",marginBottom:10,border:`1px solid ${t.border}`}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:5}}><span style={{fontSize:12,color:t.accent,fontWeight:700}}>zyno.chat/join/{l.link_token?.slice(0,10)}...</span><div style={{display:"flex",gap:8}}><button onClick={()=>navigator.clipboard?.writeText(`https://zyno.chat/join/${l.link_token}`)} style={{padding:"4px 10px",borderRadius:8,background:t.card,border:`1px solid ${t.border}`,cursor:"pointer",fontSize:11,color:t.text,fontWeight:600}}>Copy</button><button onClick={()=>revokeLink(l.id)} style={{padding:"4px 10px",borderRadius:8,background:`${t.red}18`,border:`1px solid ${t.red}30`,cursor:"pointer",fontSize:11,color:t.red,fontWeight:600}}>Revoke</button></div></div>
          <div style={{fontSize:11,color:t.textSub}}>{l.uses_count||0} uses{l.expires_at?` · Expires ${new Date(l.expires_at).toLocaleDateString()}`:""}</div>
        </div>)}
        {!inviteLinks.length&&<div style={{textAlign:"center",color:t.textSub,padding:30,fontSize:13}}>No active invite links</div>}
      </>}
      {tab==="settings"&&[["Slow Mode",Timer,t.orange],["Topics/Threads",Hash,t.accent],["Who Can Send",Edit3,t.purple],["Admin Permissions",Crown,t.yellow],["Restricted Words",Shield,t.red],["Chat History",Archive,t.textSub]].map(([l,Ic,c])=><button key={l} style={{display:"flex",alignItems:"center",gap:12,padding:"14px",background:t.surface,border:`1px solid ${t.border}`,borderRadius:12,cursor:"pointer",textAlign:"left",width:"100%",marginBottom:8}}><div style={{width:36,height:36,borderRadius:11,background:`${c}18`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Ic size={16} color={c}/></div><span style={{fontWeight:600,color:t.text,fontSize:13,flex:1}}>{l}</span><ChevronRight size={15} color={t.muted}/></button>)}
    </div>
  </div>;
}

// ═══════════════════════════════════════════════════════
// PAGES (Home, Chats, Search, Profile, Settings)
// ═══════════════════════════════════════════════════════
function HomePage({profile,openSheet,stories,onViewStory,onAddStory}){
  const t=T();
  const menu=[{icon:HelpCircle,label:"#help",desc:"Get direct team support",color:t.accent,bg:`${t.accent}18`,key:"help"},{icon:MessageCircle,label:"#support",desc:"Community 24/7 help",color:t.green,bg:`${t.green}18`,key:"support"},{icon:Bot,label:"#ai",desc:"ZynoAI powered by Claude",color:t.orange,bg:`${t.orange}18`,key:"ai"},{icon:Megaphone,label:"#updates",desc:"Official announcements",color:t.purple,bg:`${t.purple}18`,key:"updates"},{icon:Flag,label:"#report",desc:"Report abuse or spam",color:t.red,bg:`${t.red}18`,key:"report"}];
  return <div style={{flex:1,overflowY:"auto"}}>
    <StoryBar profile={profile} onView={onViewStory} onAdd={onAddStory} stories={stories}/>
    <div style={{padding:"0 12px 14px"}}><div style={{borderRadius:20,overflow:"hidden",position:"relative",background:"linear-gradient(135deg,#0a1628,#100c30)",border:`1px solid ${t.border}`}}><div style={{position:"absolute",inset:0,background:`radial-gradient(ellipse at 15% 50%,${t.purple}28,transparent 55%),radial-gradient(ellipse at 85% 50%,${t.accent}18,transparent 55%)`}}/><div style={{padding:"16px 18px 10px",position:"relative",zIndex:1,display:"flex",gap:14,alignItems:"center"}}><div style={{flex:1}}><div style={{fontSize:9,color:t.accent,fontWeight:800,letterSpacing:2.5,textTransform:"uppercase",marginBottom:7,display:"flex",alignItems:"center",gap:5}}><Lightning size={9} fill={t.accent}/>ZYNO PREMIUM</div><div style={{fontSize:18,fontWeight:800,color:t.text,fontFamily:"'Sora',sans-serif",lineHeight:1.3}}>Unlock everything<br/><span style={{background:t.grad,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>for ₹199/month</span></div><div style={{fontSize:11,color:t.textSub,marginTop:5}}>Secret chats · 2GB files · Analytics · AI credits</div></div><div style={{width:64,height:64,borderRadius:20,background:"linear-gradient(135deg,#f5c542,#ff8c42)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 0 28px #f5c54260",flexShrink:0}}><Crown size={32} color="#fff" fill="#fff"/></div></div><div style={{padding:"8px 18px 18px",display:"flex",gap:8,position:"relative",zIndex:1}}><button onClick={()=>openSheet("premium")} style={{flex:1,padding:"9px",borderRadius:12,background:t.grad,border:"none",cursor:"pointer",color:"#fff",fontSize:13,fontWeight:700,fontFamily:"'Sora',sans-serif"}}>Upgrade Now</button><button style={{flex:1,padding:"9px",borderRadius:12,background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.15)",cursor:"pointer",color:t.textSub,fontSize:13,fontWeight:700,fontFamily:"'Sora',sans-serif"}}>Learn More</button></div></div></div>
    <div style={{padding:"0 12px"}}><div style={{fontSize:10,color:t.textSub,fontWeight:700,letterSpacing:2,textTransform:"uppercase",marginBottom:10,fontFamily:"'Sora',sans-serif"}}>Quick Access</div><div style={{borderRadius:18,overflow:"hidden",background:t.surface,border:`1px solid ${t.border}`}}>{menu.map((item,i)=><button key={item.key} onClick={()=>openSheet(item.key)} style={{display:"flex",alignItems:"center",gap:14,padding:"14px 16px",background:"transparent",border:"none",cursor:"pointer",width:"100%",borderBottom:i<menu.length-1?`1px solid ${t.border}`:"none",transition:"background .15s"}} onMouseEnter={e=>e.currentTarget.style.background=t.card} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><div style={{width:44,height:44,borderRadius:14,background:item.bg,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><item.icon size={20} color={item.color}/></div><div style={{flex:1,textAlign:"left"}}><div style={{fontFamily:"'Sora',sans-serif",fontWeight:700,color:t.text,fontSize:14}}>{item.label}</div><div style={{fontSize:11,color:t.textSub,marginTop:1}}>{item.desc}</div></div><ChevronRight size={15} color={t.muted}/></button>)}</div></div>
    <div style={{height:100}}/>
  </div>;
}

function ChatsPage({profile,openChat,openCreate}){
  const t=T();const [chats,setChats]=useState([]);const [folder,setFolder]=useState("all");const [loading,setLoading]=useState(true);const [typing,setTyping]=useState({});
  const folders=[{id:"all",label:"All"},{id:"personal",label:"DMs"},{id:"group",label:"Groups"},{id:"channel",label:"Channels"},{id:"unread",label:"Unread"}];
  const load=useCallback(async()=>{setLoading(true);const {data:m}=await sb.from("chat_members").select("chat_id").eq("user_id",profile.id);if(!m?.length){setChats([]);setLoading(false);return;}const ids=m.map(x=>x.chat_id);const {data}=await sb.from("chats").select("*").in("id",ids).order("last_message_at",{ascending:false});setChats(data||[]);setLoading(false);},[profile.id]);
  useEffect(()=>{load();},[load]);
  useEffect(()=>sb.realtime("chats",({type:ev,record})=>{if(ev==="UPDATE")setChats(p=>p.map(c=>c.id===record.id?{...c,...record}:c).sort((a,b)=>new Date(b.last_message_at)-new Date(a.last_message_at)));if(ev==="INSERT")load();}),[load]);
  useEffect(()=>{const ch=sb.channel("typ_global");ch.on("typing",({user_id,chat_id,name})=>{if(user_id!==profile.id){setTyping(p=>({...p,[chat_id]:name||"Someone"}));setTimeout(()=>setTyping(p=>{const n={...p};delete n[chat_id];return n;}),3500);}}).subscribe();return()=>ch.unsubscribe();},[profile.id]);
  const filtered=useMemo(()=>{if(folder==="all")return chats;if(folder==="unread")return chats.filter(c=>(c.unread_count||0)>0);return chats.filter(c=>c.type===folder);},[chats,folder]);
  const typeIcon=tp=>({channel:<Megaphone size={10} color="#0ea5e9"/>,group:<Users size={10} color={t.green}/>,bot:<Bot size={10} color={t.orange}/>}[tp]||null);
  const fmt=ts=>{if(!ts)return"";const d=new Date(ts),n=new Date(),diff=(n-d)/86400000;if(diff<1)return d.toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"});if(diff<7)return d.toLocaleDateString([],{weekday:"short"});return d.toLocaleDateString([],{day:"2-digit",month:"2-digit"});};
  return <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
    <div style={{padding:"6px 12px 0",overflowX:"auto",flexShrink:0}}><div style={{display:"flex",gap:6,paddingBottom:8}}>{folders.map(f=><button key={f.id} onClick={()=>setFolder(f.id)} style={{padding:"7px 16px",borderRadius:20,border:"none",flexShrink:0,cursor:"pointer",fontFamily:"'Sora',sans-serif",fontWeight:700,fontSize:12,transition:"all .2s",background:folder===f.id?t.grad:t.surface,color:folder===f.id?"#fff":t.textSub}}>{f.label}</button>)}</div></div>
    <div style={{flex:1,overflowY:"auto"}}>
      {loading?<div style={{display:"flex",justifyContent:"center",padding:50}}><Spin/></div>
      :filtered.length===0?<div style={{textAlign:"center",padding:60,color:t.textSub,fontFamily:"'Sora',sans-serif",display:"flex",flexDirection:"column",alignItems:"center",gap:14}}><MessageCircle size={52} style={{opacity:0.12}}/><div style={{fontWeight:700,fontSize:16}}>No chats yet</div><Btn small icon={Plus} onClick={()=>openCreate("group")}>New Group</Btn></div>
      :filtered.map(chat=>{const isTyp=!!typing[chat.id];const uc=chat.unread_count||0;return <button key={chat.id} onClick={()=>openChat(chat)} style={{display:"flex",alignItems:"center",gap:13,padding:"13px 14px",background:"transparent",border:"none",cursor:"pointer",width:"100%",borderBottom:`1px solid ${t.border}`,transition:"background .14s"}} onMouseEnter={e=>e.currentTarget.style.background=t.surface} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
        <Av name={chat.name||"?"} color={chat.avatar_color||t.purple} url={chat.avatar_url} size={54} online={chat.type==="personal"}/>
        <div style={{flex:1,minWidth:0,textAlign:"left"}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:4}}>
            <div style={{display:"flex",alignItems:"center",gap:5}}>{typeIcon(chat.type)}<span style={{fontFamily:"'Sora',sans-serif",fontWeight:700,color:t.text,fontSize:14,maxWidth:170,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{chat.name}</span>{chat.is_verified&&<Vtick/>}</div>
            <div style={{display:"flex",alignItems:"center",gap:6,flexShrink:0}}><span style={{fontSize:10,color:t.muted,fontFamily:"'Sora',sans-serif"}}>{fmt(chat.last_message_at)}</span>{uc>0&&<Badge n={uc}/>}</div>
          </div>
          <div style={{fontSize:12,color:isTyp?t.accent:t.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontStyle:isTyp?"italic":"normal",fontFamily:"'Sora',sans-serif"}}>{isTyp?`${typing[chat.id]} is typing...`:chat.last_message_text||"Start conversation"}</div>
        </div>
      </button>;})}
    </div>
    <div style={{position:"fixed",bottom:80,right:16,display:"flex",flexDirection:"column",gap:10,alignItems:"flex-end",zIndex:20}}>
      <Btn small icon={Megaphone} onClick={()=>openCreate("channel")} style={{boxShadow:`0 4px 18px ${t.accent}40`}}>Channel</Btn>
      <Btn small icon={Users} variant="success" onClick={()=>openCreate("group")}>Group</Btn>
    </div>
  </div>;
}

function SearchPage({profile,openChat}){
  const t=T();const [q,setQ]=useState("");const [res,setRes]=useState({channels:[],groups:[],bots:[],users:[]});const [loading,setLoading]=useState(false);const recent=["@techcafe","Coding India","Arjun Mehta","ZynoChat Support"];
  useEffect(()=>{if(!q.trim()){setRes({channels:[],groups:[],bots:[],users:[]});return;}const x=setTimeout(async()=>{setLoading(true);const pat=`%${q}%`;const [{data:ch},{data:us}]=await Promise.all([sb.from("chats").select("*").or(`name.ilike.${pat},username.ilike.${pat}`).eq("is_public",true).limit(30),sb.from("profiles").select("*").or(`full_name.ilike.${pat},username.ilike.${pat}`).limit(10)]);const r={channels:[],groups:[],bots:[],users:us||[]};(ch||[]).forEach(x=>{if(x.type==="channel")r.channels.push(x);else if(x.type==="group")r.groups.push(x);else if(x.type==="bot")r.bots.push(x);});setRes(r);setLoading(false);},350);return()=>clearTimeout(x);},[q]);
  const join=async chat=>{const {data:ex}=await sb.from("chat_members").select("id").eq("chat_id",chat.id).eq("user_id",profile.id).limit(1);if(!Array.isArray(ex)||!ex.length)await sb.from("chat_members").insert({chat_id:chat.id,user_id:profile.id,role:"member"});openChat(chat);};
  const Sec=({title,items,isUser})=>{if(!items.length)return null;return <div style={{marginBottom:20}}><div style={{fontSize:10,color:t.textSub,fontWeight:700,letterSpacing:2,textTransform:"uppercase",marginBottom:10,fontFamily:"'Sora',sans-serif"}}>{title}</div><div style={{borderRadius:14,overflow:"hidden",background:t.surface,border:`1px solid ${t.border}`}}>{items.map((item,i)=><div key={item.id} style={{display:"flex",alignItems:"center",gap:12,padding:"13px 14px",borderBottom:i<items.length-1?`1px solid ${t.border}`:"none"}}><Av name={isUser?item.full_name:item.name} color={item.avatar_color||t.purple} size={48} online={isUser&&item.is_online}/><div style={{flex:1,minWidth:0}}><div style={{display:"flex",alignItems:"center",gap:4}}><span style={{fontWeight:700,color:t.text,fontSize:14,fontFamily:"'Sora',sans-serif"}}>{isUser?item.full_name:item.name}</span>{item.is_verified&&<Vtick/>}</div><div style={{fontSize:11,color:t.textSub,marginTop:1}}>{item.username?`@${item.username}`:""}{!isUser&&` · ${(item.member_count||0).toLocaleString()} members`}</div></div>{!isUser&&<Btn small variant="ghost" onClick={()=>join(item)}>Join</Btn>}{isUser&&<Btn small variant="ghost" onClick={()=>{}}>Message</Btn>}</div>)}</div></div>;};
  return <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
    <div style={{padding:"10px 12px 0"}}><div style={{display:"flex",alignItems:"center",gap:10,background:t.surface,borderRadius:16,padding:"11px 16px",border:`1px solid ${t.border}`}}><Search size={16} color={t.textSub}/><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Search people, groups, channels..." autoFocus style={{flex:1,background:"none",border:"none",outline:"none",color:t.text,fontSize:14,fontFamily:"'Sora',sans-serif",caretColor:t.accent}}/>{q&&<button onClick={()=>setQ("")} style={{background:"none",border:"none",cursor:"pointer",color:t.muted}}><X size={14}/></button>}</div></div>
    <div style={{flex:1,overflowY:"auto",padding:"14px 12px 100px"}}>{loading?<div style={{display:"flex",justifyContent:"center",padding:40}}><Spin/></div>:!q?<div><div style={{fontSize:10,color:t.textSub,fontWeight:700,letterSpacing:2,textTransform:"uppercase",marginBottom:10,fontFamily:"'Sora',sans-serif"}}>Recent Searches</div><div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:24}}>{recent.map(r=><button key={r} onClick={()=>setQ(r)} style={{padding:"7px 14px",borderRadius:12,background:t.surface,border:`1px solid ${t.border}`,color:t.text,fontSize:13,cursor:"pointer",fontFamily:"'Sora',sans-serif",fontWeight:600,display:"flex",alignItems:"center",gap:6}}><Clock size={12} color={t.textSub}/>{r}</button>)}</div><div style={{textAlign:"center",color:t.textSub,padding:"20px 0",display:"flex",flexDirection:"column",alignItems:"center",gap:10}}><Search size={44} style={{opacity:0.12}}/><div style={{fontWeight:700,fontSize:15,fontFamily:"'Sora',sans-serif"}}>Explore ZynoChat</div></div></div>:<><Sec title="👤 People" items={res.users} isUser/><Sec title="📡 Channels" items={res.channels}/><Sec title="👥 Groups" items={res.groups}/><Sec title="🤖 Bots" items={res.bots}/>{!res.users.length&&!res.channels.length&&!res.groups.length&&!res.bots.length&&<div style={{textAlign:"center",color:t.textSub,padding:50,fontFamily:"'Sora',sans-serif"}}><Search size={44} style={{opacity:0.12,marginBottom:12}}/><div style={{fontWeight:700,fontSize:15}}>No results for "{q}"</div></div>}</>}</div>
  </div>;
}

function ProfilePage({profile,onRefresh}){
  const t=T();const [editing,setEditing]=useState(false);const [saving,setSaving]=useState(false);const [fol,setFol]=useState(0);const [ing,setIng]=useState(0);const [stories,setStories]=useState([]);const [form,setForm]=useState({full_name:profile.full_name||"",bio:profile.bio||"",location:profile.location||"",website:profile.website||""});const set=k=>e=>setForm(f=>({...f,[k]:e.target.value}));
  useEffect(()=>{sb.from("contacts").select("id").eq("following_id",profile.id).then(({data})=>setFol(data?.length||0));sb.from("contacts").select("id").eq("follower_id",profile.id).then(({data})=>setIng(data?.length||0));sb.from("stories").select("*").eq("user_id",profile.id).gte("expires_at",new Date().toISOString()).then(({data})=>setStories(data||[]));},[profile.id]);
  const save=async()=>{setSaving(true);await sb.from("profiles").update(form).eq("id",profile.id);setSaving(false);setEditing(false);onRefresh?.();};
  const hue=(profile.username||"a").charCodeAt(0)%360;
  return <div style={{flex:1,overflowY:"auto"}}>
    <div style={{height:110,background:`hsl(${hue},55%,13%)`,position:"relative",flexShrink:0}}><div style={{position:"absolute",inset:0,background:`radial-gradient(circle at 30% 50%,hsl(${hue},70%,38%)26,transparent 65%),radial-gradient(circle at 70% 50%,hsl(${(hue+120)%360},60%,30%)18,transparent 65%)`}}/><div style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.22)"}}/></div>
    <div style={{padding:"0 16px",marginTop:-54}}>
      <div style={{display:"flex",alignItems:"flex-end",justifyContent:"space-between",marginBottom:14}}><div style={{borderRadius:"50%",border:`3.5px solid ${t.bg}`}}><Av name={profile.full_name||"?"} color={profile.avatar_color||t.purple} size={86} ring online/></div><div style={{display:"flex",gap:8,marginBottom:10}}><button onClick={()=>setEditing(!editing)} style={{padding:"8px 18px",borderRadius:12,background:editing?t.grad:t.surface,border:`1px solid ${editing?t.purple:t.border}`,color:editing?"#fff":t.text,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Sora',sans-serif"}}>{editing?"Cancel":"Edit"}</button><button onClick={()=>navigator.clipboard?.writeText(`https://zyno.chat/@${profile.username}`)} style={{padding:"8px",borderRadius:12,background:t.surface,border:`1px solid ${t.border}`,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}><QrCode size={17} color={t.textSub}/></button></div></div>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3}}><span style={{fontFamily:"'Sora',sans-serif",fontWeight:800,color:t.text,fontSize:22}}>{profile.full_name}</span>{profile.is_verified&&<Vtick/>}{profile.role&&profile.role!=="user"&&<span style={{background:t.grad,color:"#fff",fontSize:9,fontWeight:700,padding:"2px 9px",borderRadius:7}}>{profile.role.toUpperCase()}</span>}{profile.premium_until&&<span style={{background:"linear-gradient(135deg,#f5c542,#ff8c42)",color:"#fff",fontSize:9,fontWeight:700,padding:"2px 8px",borderRadius:7}}>PREMIUM</span>}</div>
      <div style={{color:t.textSub,fontSize:13,marginBottom:12}}>@{profile.username}</div>
      <div style={{display:"flex",gap:28,marginBottom:14}}>{[{l:"Stories",v:stories.length},{l:"Followers",v:fol},{l:"Following",v:ing}].map(s=><div key={s.l} style={{textAlign:"center"}}><div style={{fontFamily:"'Sora',sans-serif",fontWeight:800,color:t.text,fontSize:19}}>{s.v.toLocaleString()}</div><div style={{fontSize:10,color:t.textSub,marginTop:1}}>{s.l}</div></div>)}</div>
      {!editing?<div style={{background:t.surface,borderRadius:14,padding:"12px 14px",border:`1px solid ${t.border}`,marginBottom:12}}>{profile.bio?<p style={{margin:0,fontSize:13,color:t.text,lineHeight:1.75,fontFamily:"'Sora',sans-serif"}}>{profile.bio}</p>:<p style={{margin:0,fontSize:13,color:t.muted,fontStyle:"italic",fontFamily:"'Sora',sans-serif"}}>Add a bio to introduce yourself...</p>}{profile.location&&<div style={{display:"flex",alignItems:"center",gap:6,marginTop:8,fontSize:12,color:t.textSub}}><MapPin size={12}/>{profile.location}</div>}{profile.website&&<div style={{display:"flex",alignItems:"center",gap:6,marginTop:5,fontSize:12,color:t.accent}}><ExternalLink size={11}/>{profile.website}</div>}</div>
      :<div style={{background:t.surface,borderRadius:14,padding:16,border:`1px solid ${t.border}`,marginBottom:12}}><Inp label="Display Name" icon={User} value={form.full_name} onChange={set("full_name")}/><Inp label="Bio" icon={Edit3} value={form.bio} onChange={set("bio")} placeholder="Tell people about yourself..." multiline rows={2}/><Inp label="Location" icon={MapPin} value={form.location} onChange={set("location")} placeholder="City, Country"/><Inp label="Website" icon={Link} value={form.website} onChange={set("website")} placeholder="https://yoursite.com"/><Btn full onClick={save} loading={saving} style={{justifyContent:"center"}}>Save Changes</Btn></div>}
      <div style={{background:t.surface,borderRadius:14,padding:"12px 14px",border:`1px solid ${t.border}`,marginBottom:14,display:"flex",alignItems:"center",justifyContent:"space-between"}}><div><div style={{fontSize:12,fontWeight:700,color:t.text,fontFamily:"'Sora',sans-serif"}}>Profile Link</div><div style={{fontSize:11,color:t.textSub,marginTop:1}}>zyno.chat/@{profile.username}</div></div><div style={{display:"flex",gap:6}}><button onClick={()=>navigator.clipboard?.writeText(`https://zyno.chat/@${profile.username}`)} style={{padding:"6px 12px",borderRadius:9,background:t.grad,border:"none",cursor:"pointer",color:"#fff",fontSize:11,fontWeight:700,fontFamily:"'Sora',sans-serif"}}>Copy</button><button style={{padding:"6px",borderRadius:9,background:t.card,border:`1px solid ${t.border}`,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}><Share2 size={15} color={t.textSub}/></button></div></div>
      {stories.length>0&&<><div style={{fontSize:10,color:t.textSub,fontWeight:700,letterSpacing:2,textTransform:"uppercase",marginBottom:10,fontFamily:"'Sora',sans-serif"}}>Active Stories</div><div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:5,marginBottom:16}}>{stories.map(s=><div key={s.id} style={{aspectRatio:"1",borderRadius:13,background:s.bg_color||t.card,display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden",border:`1px solid ${t.border}`,cursor:"pointer"}}><span style={{fontSize:11,color:"#fff",padding:6,textAlign:"center",fontWeight:700,fontFamily:"'Sora',sans-serif"}}>{s.content?.slice(0,18)||"🌟"}</span></div>)}</div></>}
    </div>
    <div style={{height:100}}/>
  </div>;
}

function SettingsPage({profile,onLogout,openAdmin,onSecurity,themeKey,onThemeChange}){
  const t=T();const [priv,setPriv]=useState({phone:"nobody",lastSeen:"contacts",photo:"everyone",bio:"everyone",stories:"contacts",groups:"everyone"});const [notif,setNotif]=useState({messages:true,groups:true,channels:true,sounds:true,previews:true,vibrate:true});
  useEffect(()=>{if(profile)setPriv(p=>({...p,phone:profile.priv_phone||"nobody",lastSeen:profile.priv_lastseen||"contacts",photo:profile.priv_photo||"everyone",bio:profile.priv_bio||"everyone",stories:profile.priv_stories||"contacts",groups:profile.priv_groups||"everyone"}));},[profile]);
  const saveP=async(k,v,col)=>{setPriv(p=>({...p,[k]:v}));await sb.from("profiles").update({[col]:v}).eq("id",profile.id);};
  const opts=["everyone","contacts","nobody"];
  const PRow=({label,icon:Icon,color,sk,col})=>{const [op,setOp]=useState(false);const val=priv[sk];return <div style={{borderBottom:`1px solid ${t.border}`}}><button onClick={()=>setOp(!op)} style={{display:"flex",alignItems:"center",gap:12,padding:"13px 16px",width:"100%",background:"none",border:"none",cursor:"pointer"}}><div style={{width:38,height:38,borderRadius:12,background:`${color}18`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Icon size={16} color={color}/></div><div style={{flex:1,textAlign:"left"}}><div style={{fontFamily:"'Sora',sans-serif",fontWeight:600,color:t.text,fontSize:13}}>{label}</div><div style={{fontSize:11,color:t.textSub,textTransform:"capitalize",marginTop:1}}>{val}</div></div><ChevronDown size={14} color={t.muted} style={{transform:op?"rotate(180deg)":"none",transition:".2s"}}/></button>{op&&<div style={{background:t.card,margin:"0 14px 10px",borderRadius:12,overflow:"hidden",border:`1px solid ${t.border}`}}>{opts.map(o=><button key={o} onClick={()=>{saveP(sk,o,col);setOp(false);}} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 14px",width:"100%",background:"none",border:"none",cursor:"pointer",borderBottom:`1px solid ${t.border}`,fontFamily:"'Sora',sans-serif",color:val===o?t.accent:t.text,fontSize:13,fontWeight:val===o?700:500}}><span style={{textTransform:"capitalize"}}>{o}</span>{val===o&&<Check size={13} color={t.accent}/>}</button>)}</div>}</div>;};
  const NRow=({label,icon:Icon,color,sk})=><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"13px 16px",borderBottom:`1px solid ${t.border}`}}><div style={{display:"flex",alignItems:"center",gap:12}}><div style={{width:38,height:38,borderRadius:12,background:`${color}18`,display:"flex",alignItems:"center",justifyContent:"center"}}><Icon size={16} color={color}/></div><span style={{fontFamily:"'Sora',sans-serif",fontWeight:600,color:t.text,fontSize:13}}>{label}</span></div><Toggle on={notif[sk]} onChange={v=>setNotif(p=>({...p,[sk]:v}))} color={color}/></div>;
  const Sec=({title,children})=><div style={{marginBottom:20}}><div style={{fontSize:10,color:t.textSub,fontWeight:700,letterSpacing:2,textTransform:"uppercase",marginBottom:8,fontFamily:"'Sora',sans-serif"}}>{title}</div><div style={{borderRadius:16,overflow:"hidden",background:t.surface,border:`1px solid ${t.border}`}}>{children}</div></div>;
  return <div style={{flex:1,overflowY:"auto"}}><div style={{padding:"12px 12px 0"}}>
    <div style={{borderRadius:18,background:t.surface,border:`1px solid ${t.border}`,padding:"16px",marginBottom:20,display:"flex",alignItems:"center",gap:14}}><Av name={profile.full_name||"?"} color={profile.avatar_color||t.purple} size={60} ring online/><div style={{flex:1,minWidth:0}}><div style={{fontWeight:800,color:t.text,fontSize:17,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontFamily:"'Sora',sans-serif"}}>{profile.full_name}</div><div style={{fontSize:12,color:t.textSub,marginTop:1}}>@{profile.username}</div>{profile.premium_until&&<div style={{fontSize:10,color:t.yellow,display:"flex",alignItems:"center",gap:4,marginTop:4}}><Crown size={10} fill={t.yellow}/>Premium active</div>}</div><div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:3}}><div style={{width:9,height:9,borderRadius:"50%",background:t.green,boxShadow:`0 0 8px ${t.green}`}}/><span style={{fontSize:10,color:t.green,fontWeight:700,fontFamily:"'Sora',sans-serif"}}>Online</span></div></div>
    <Sec title="Appearance">
      <div style={{padding:"14px 16px",borderBottom:`1px solid ${t.border}`}}><div style={{fontWeight:600,color:t.text,fontSize:13,marginBottom:10,fontFamily:"'Sora',sans-serif"}}>App Theme</div><div style={{display:"flex",gap:10}}>{Object.entries(THEMES).map(([tk,tv])=><button key={tk} onClick={()=>onThemeChange(tk)} style={{flex:1,padding:"12px 6px",borderRadius:13,border:`2px solid ${themeKey===tk?tv.purple:t.border}`,background:tv.surface,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:6}}><div style={{width:24,height:24,borderRadius:8,background:tv.grad,boxShadow:themeKey===tk?`0 2px 10px ${tv.purple}50`:""}}/><span style={{fontSize:10,color:tv.text,fontWeight:700,fontFamily:"'Sora',sans-serif",textTransform:"capitalize"}}>{tk}</span></button>)}</div></div>
      <NRow label="Animated Effects" icon={Palette} color={t.accent} sk="previews"/>
    </Sec>
    <Sec title="Notifications"><NRow label="Messages" icon={MessageCircle} color={t.accent} sk="messages"/><NRow label="Groups" icon={Users} color={t.green} sk="groups"/><NRow label="Channels" icon={Megaphone} color={t.purple} sk="channels"/><NRow label="Sounds" icon={Volume2} color={t.orange} sk="sounds"/><NRow label="Vibrate" icon={Smartphone} color={t.textSub} sk="vibrate"/></Sec>
    <Sec title="Privacy"><PRow label="Phone Number" icon={Phone} color={t.accent} sk="phone" col="priv_phone"/><PRow label="Last Seen" icon={Eye} color={t.green} sk="lastSeen" col="priv_lastseen"/><PRow label="Profile Photo" icon={Camera} color={t.orange} sk="photo" col="priv_photo"/><PRow label="Bio" icon={Edit3} color={t.purple} sk="bio" col="priv_bio"/><PRow label="Stories" icon={PlayCircle} color={t.pink} sk="stories" col="priv_stories"/><PRow label="Groups" icon={Users} color={t.teal} sk="groups" col="priv_groups"/></Sec>
    <button onClick={onSecurity} style={{width:"100%",padding:"15px 16px",borderRadius:16,background:`linear-gradient(135deg,${t.red}15,${t.orange}08)`,border:`1px solid ${t.red}30`,cursor:"pointer",display:"flex",alignItems:"center",gap:12,marginBottom:14,textAlign:"left"}}><div style={{width:44,height:44,borderRadius:14,background:`${t.red}22`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><ShieldCheck size={22} color={t.red}/></div><div style={{flex:1}}><div style={{fontWeight:700,color:t.text,fontSize:14,fontFamily:"'Sora',sans-serif"}}>Security Center</div><div style={{fontSize:11,color:t.textSub,marginTop:1}}>2FA · Sessions · Login history · Passcode</div></div><ChevronRight size={15} color={t.red}/></button>
    <button onClick={openAdmin} style={{width:"100%",padding:"15px 16px",borderRadius:16,background:`linear-gradient(135deg,${t.purple}15,${t.accent}08)`,border:`1px solid ${t.purple}40`,cursor:"pointer",display:"flex",alignItems:"center",gap:12,marginBottom:14,textAlign:"left"}}><div style={{width:44,height:44,borderRadius:14,background:`${t.purple}22`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Crown size={22} color={t.yellow} fill={t.yellow}/></div><div style={{flex:1}}><div style={{fontWeight:700,color:t.text,fontSize:14,fontFamily:"'Sora',sans-serif"}}>Admin Panel</div><div style={{fontSize:11,color:t.textSub,marginTop:1}}>Manage platform · Analytics · Moderation</div></div><ChevronRight size={15} color={t.purple}/></button>
    <button onClick={onLogout} style={{width:"100%",padding:"13px",borderRadius:14,background:`${t.red}10`,border:`1px solid ${t.red}30`,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8,marginBottom:100}}><LogOut size={16} color={t.red}/><span style={{fontFamily:"'Sora',sans-serif",fontWeight:700,color:t.red,fontSize:14}}>Sign Out</span></button>
  </div></div>;
}

